            transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .avatar-container:hover .user-avatar { transform: scale(1.05); box-shadow: 0 0 25px var(--c-gold); border-color: var(--c-gold-shine); }
        .avatar-container:hover::before { border-color: var(--c-gold); border-style: solid; animation: spin 4s linear infinite; inset: -10px; opacity: 0.8; }

        .ctrl-btn-group {
            position: absolute; bottom: -10px; left: 50%; transform: translateX(-50%);
            display: flex; gap: 5px; z-index: 10;
        }
        .mini-btn {
            width: 24px; height: 24px;
            background: rgba(0,0,0,0.8);
            border: 1px solid var(--c-gold);
            border-radius: 50%;
            color: var(--c-gold);
            display: flex; justify-content: center; align-items: center;
            font-size: 10px;
            cursor: pointer;
            transition: all 0.3s;
        }
        .mini-btn:hover { background: var(--c-gold); color: #000; transform: scale(1.1); }

        .info-group { display: flex; flex-direction: column; justify-content: center; width: 100%; }
        .p-name {
            font-size: 24px; color: var(--c-gold-shine); font-weight: 700;
            font-family: var(--f-eng); letter-spacing: 1px;
            text-shadow: 0 2px 4px #000;
        }

        .title-badges { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 6px; }
        .t-badge {
            font-size: 10px; padding: 2px 8px; border-radius: 2px;
            border: 1px solid; display: flex; align-items: center; gap: 4px;
            white-space: nowrap; max-width: 200px; overflow: hidden; text-overflow: ellipsis;
            backdrop-filter: blur(4px); transition: all 0.3s;
        }
        .tb-title { border-color: var(--c-gold); background: rgba(200,170,110,0.1); color: var(--c-gold); }
        .tb-rep { border-color: var(--c-sub); background: rgba(138, 99, 204, 0.15); color: #bca0dc; }
        .tb-norm { border-color: #555; color: #888; border-style: dashed; }

        .resource-group { display: flex; gap: 15px; }
        .res-box {
            background: linear-gradient(135deg, rgba(30,20,40,0.8), rgba(10,5,10,0.9));
            border: 1px solid var(--c-gold-dim);
            padding: 8px 15px;
            display: flex; align-items: center; gap: 12px;
            min-width: 110px; position: relative;
            clip-path: polygon(10px 0, 100% 0, 100% 100%, 0 100%, 0 10px);
            transition: all 0.3s;
        }
        .res-box:hover { background: rgba(50, 40, 60, 0.9); border-color: var(--c-gold); transform: translateY(-2px); }
        .res-box::before { content:''; position: absolute; left:0; top:0; width:3px; height:100%; background: var(--c-gold); }
        .res-icon { font-size: 20px; width: 24px; text-align: center; flex-shrink: 0; }
        .res-info { display: flex; flex-direction: column; align-items: flex-start; justify-content: center; min-width: 0; }
        /* Sửa đổi thích ứng: Bắt buộc không xuống dòng, và giảm cỡ chữ để phù hợp với văn bản dài */
        .rn {
            font-size: 14px; font-weight: bold; color: #fff; font-family: var(--f-eng); line-height: 1.2;
            white-space: nowrap; overflow: hidden; text-overflow: ellipsis; max-width: 100%;
        }
        .rl { font-size: 10px; color: #888; margin-top: 2px; white-space: nowrap; }
        .t-origin .res-icon { color: #e67e22; }
        .t-mana .res-icon { color: var(--c-blue-mana); }
        .t-rank .res-icon { color: var(--c-red-alert); }

        /* ==================== Style chung cho bảng ==================== */
        .side-panel {
            position: fixed; background: var(--c-panel-bg);
            border: 1px solid var(--c-gold-dim);
            box-shadow: 5px 0 30px rgba(0,0,0,0.5);
            z-index: 200; backdrop-filter: blur(10px);
            transition: all 0.4s var(--ease-out);
            display: flex; flex-direction: column;
            padding: 15px;
        }
        .panel-h {
            font-size: 14px; font-weight: bold; color: var(--c-gold);
            margin-bottom: 10px; padding-bottom: 5px;
            border-bottom: 1px solid rgba(255,255,255,0.1);
            display: flex; justify-content: space-between; align-items: center;
        }
        .panel-h i { cursor: pointer; transition: 0.3s; }
        .panel-h i:hover { color: #fff; }

        /* ==================== Bảng cài đặt ==================== */
        #settings-panel {
            right: -320px; top: 80px; width: 300px; bottom: 80px;
            border-right: none; border-left: 1px solid var(--c-gold-dim);
            border-radius: 10px 0 0 10px;
        }
        #settings-panel.active { right: 0; }

        .setting-group { margin-bottom: 20px; }
        .st-label { font-size: 12px; color: #888; margin-bottom: 8px; font-weight: bold; }
        .st-options { display: flex; gap: 8px; flex-wrap: wrap; }
        .st-btn {
            flex: 1; min-width: 60px;
            padding: 6px 4px; text-align: center;
            border: 1px solid #444; background: rgba(0,0,0,0.3);
            color: #aaa; font-size: 11px; cursor: pointer;
            border-radius: 4px; transition: 0.2s;
        }
        .st-btn:hover { border-color: var(--c-gold-dim); color: #fff; }
        .st-btn.active { border-color: var(--c-gold); background: rgba(200,170,110,0.15); color: var(--c-gold); font-weight: bold; }
        .theme-circle { width: 30px; height: 30px; border-radius: 50%; cursor: pointer; border: 2px solid #333; position: relative; }
        .theme-circle.active { border-color: #fff; box-shadow: 0 0 8px currentColor; transform: scale(1.1); }

        /* ==================== Bảng trình phát nhạc ==================== */
        #music-panel {
            left: -320px; bottom: 80px; width: 300px;
            border-left: none;
            border-top-right-radius: 10px; border-bottom-right-radius: 10px;
            max-height: 60vh;
        }
        #music-panel.active { left: 0; }
        #music-panel::after {
            content: ''; position: absolute; top: 10px; bottom: 10px; right: 3px; width: 2px;
            background: linear-gradient(to bottom, transparent, var(--c-gold), transparent);
        }

        .mp-controls { display: flex; justify-content: center; gap: 15px; align-items: center; margin-bottom: 10px; }
        .mp-btn { color: #aaa; cursor: pointer; transition: 0.2s; font-size: 16px; }
        .mp-btn:hover { color: #fff; text-shadow: 0 0 5px var(--c-gold); }
        .mp-btn.active { color: var(--c-gold); }
        .play-btn { font-size: 24px; width: 40px; height: 40px; border: 1px solid #444; border-radius: 50%; display: flex; justify-content: center; align-items: center; }
        .play-btn:hover { border-color: var(--c-gold); background: rgba(200,170,110,0.1); }
        .mp-progress-container { width: 100%; display: flex; align-items: center; gap: 8px; font-size: 10px; color: #666; font-family: monospace; margin-bottom: 10px; }
        .mp-slider { flex: 1; -webkit-appearance: none; height: 3px; background: #333; border-radius: 2px; cursor: pointer; }
        .mp-slider::-webkit-slider-thumb { -webkit-appearance: none; width: 10px; height: 10px; border-radius: 50%; background: var(--c-gold); cursor: pointer; }
        .mp-list { flex: 1; overflow-y: auto; border: 1px solid rgba(255,255,255,0.05); background: rgba(0,0,0,0.2); margin-bottom: 10px; padding: 5px; }
        .mp-item { padding: 6px 8px; font-size: 12px; color: #ccc; border-bottom: 1px dashed rgba(255,255,255,0.05); cursor: pointer; display: flex; justify-content: space-between; align-items: center; transition: 0.2s; }
        .mp-item:hover { background: rgba(255,255,255,0.05); }
        .mp-item.active { color: var(--c-gold); background: rgba(200,170,110,0.1); }
        .mp-item .del-btn { opacity: 0; transition: 0.2s; }
        .mp-item:hover .del-btn { opacity: 1; color: #e74c3c; cursor: pointer; }
        .mp-add { display: flex; gap: 5px; }
        .mp-input { flex: 1; background: transparent; border: 1px solid #444; color: #ddd; padding: 4px 8px; font-size: 11px; border-radius: 3px; }
        .mp-add-btn { background: #333; border: 1px solid #444; color: #ddd; padding: 0 8px; font-size: 11px; cursor: pointer; border-radius: 3px; }
        .mp-add-btn:hover { border-color: var(--c-gold); color: var(--c-gold); }

        /* ==================== Sân khấu cốt lõi ==================== */
        #stage { flex: 1; position: relative; display: flex; justify-content: center; align-items: center; z-index: 10; }
        #layer-roulette { position: absolute; width: 100%; height: 100%; display: flex; justify-content: center; align-items: center; transition: all 0.6s var(--ease-out); will-change: transform, opacity; }
        #layer-roulette.shattered { opacity: 0; pointer-events: none; transform: scale(2) rotate(5deg); filter: blur(15px); }

        .compass-wrap { position: relative; width: 460px; height: 460px; display: flex; justify-content: center; align-items: center; }
        .magic-bg { position: absolute; border-radius: 50%; border: 1px solid rgba(200, 170, 110, 0.1); pointer-events: none; transition: border-color 0.5s; }
        .m1 { width: 100%; height: 100%; border: 1px dashed rgba(200,170,110,0.3); animation: spin 80s linear infinite; border-color: var(--c-gold-dim); }
        .m2 { width: 70%; height: 70%; border: 2px solid rgba(138, 99, 204, 0.2); transform: rotate(45deg); transition: transform 0.5s; border-color: var(--c-sub); opacity: 0.3; }
        .m3 { width: 120%; height: 120%; border: 1px dotted rgba(200,170,110,0.2); animation: spin-rev 100s linear infinite; border-color: var(--c-gold-dim); }

        .orb-core {
            width: 140px; height: 140px; border-radius: 50%;
            background: radial-gradient(circle at 40% 40%, var(--c-sub) 0%, var(--c-sub-dark) 80%);
            border: 1px solid var(--c-gold);
            display: flex; flex-direction: column; justify-content: center; align-items: center;
            cursor: pointer; z-index: 20;
            animation: pulse-core 4s infinite; transition: 0.3s; position: relative;
            will-change: transform, box-shadow;
        }
        .orb-core::after { content:''; position: absolute; inset: -5px; border-radius: 50%; border-top: 2px solid var(--c-gold); border-bottom: 2px solid var(--c-gold); border-left: 2px solid transparent; border-right: 2px solid transparent; animation: spin 10s linear infinite; }
        .orb-core:hover { transform: scale(1.1); box-shadow: 0 0 60px var(--c-gold); }
        .orb-label { font-size: 22px; color: var(--c-gold-shine); font-weight: 900; }
        .orb-sub { font-size: 10px; color: #aaa; margin-top: 2px; text-transform: uppercase; letter-spacing: 2px; }

        /* Bố cục vệ tinh hình ngũ giác */
        .satellite {
            position: absolute; width: 70px; height: 70px;
            background: var(--c-sub-dark); border: 1px solid var(--c-gold-dim);
            transform: rotate(45deg); display: flex; justify-content: center; align-items: center;
            cursor: pointer; z-index: 15; box-shadow: 0 0 15px rgba(0,0,0,0.5);
            transition: all 0.3s; will-change: transform;
        }
        .satellite-inner { transform: rotate(-45deg); text-align: center; }
        .satellite i { font-size: 20px; color: #887799; margin-bottom: 5px; display: block; transition: 0.3s; }
        .satellite div { font-size: 10px; color: var(--c-gold); font-weight: bold; opacity: 0.7; transition: 0.3s; }
        .satellite:hover { border-color: var(--c-gold); background: #251a30; box-shadow: 0 0 20px var(--c-gold); }
        .satellite:hover i { color: #fff; transform: scale(1.1); }
        .satellite:hover div { opacity: 1; }

        /* Hệ thống định vị ngũ giác (Bán kính khoảng 220px) */
        /* 1:Top, 2:TR, 3:BR, 4:BL, 5:TL */
        .pos-1 { transform: translate(0, -220px) rotate(45deg); }
        .pos-2 { transform: translate(209px, -68px) rotate(45deg); }
        .pos-3 { transform: translate(129px, 178px) rotate(45deg); }
        .pos-4 { transform: translate(-129px, 178px) rotate(45deg); }
        .pos-5 { transform: translate(-209px, -68px) rotate(45deg); }

        /* Hiệu ứng Hover (Giữ nguyên độ dịch chuyển) */
        .pos-1:hover { transform: translate(0, -220px) rotate(45deg) scale(1.15); }
        .pos-2:hover { transform: translate(209px, -68px) rotate(45deg) scale(1.15); }
        .pos-3:hover { transform: translate(129px, 178px) rotate(45deg) scale(1.15); }
        .pos-4:hover { transform: translate(-129px, 178px) rotate(45deg) scale(1.15); }
        .pos-5:hover { transform: translate(-209px, -68px) rotate(45deg) scale(1.15); }

        /* ==================== Bảng chi tiết ==================== */
        #layer-detail {
            position: absolute; width: 90%; height: 75%;
            display: flex; flex-direction: column;
            pointer-events: none; opacity: 0; transform: translateY(30px) scale(0.95);
            transition: all 0.4s var(--ease-out);
            z-index: 50; will-change: transform, opacity;
        }
        #layer-detail.active { opacity: 1; transform: translateY(0) scale(1); pointer-events: auto; }

        .panel-box {
            flex: 1; background: var(--c-panel-bg);
            border: 1px solid var(--c-gold-dim);
            box-shadow: 0 20px 50px rgba(0,0,0,0.8);
            display: flex; flex-direction: column;
            backdrop-filter: blur(15px);
            position: relative; overflow: hidden;
        }
        .panel-header {
            padding: 15px 25px; border-bottom: 1px solid rgba(255,255,255,0.08);
            display: flex; justify-content: space-between; align-items: center;
            background: rgba(255,255,255,0.02);
        }
        .panel-title { font-size: 20px; color: var(--c-gold-shine); font-family: var(--f-main); font-weight: bold; display: flex; align-items: center; gap: 10px; }
        .close-btn { width: 30px; height: 30px; display: flex; align-items: center; justify-content: center; border: 1px solid #444; color: #888; cursor: pointer; transition: 0.3s; z-index: 20; }
        .close-btn:hover { border-color: var(--c-gold); color: #fff; background: var(--c-red-alert); }
        .panel-content { flex: 1; overflow-y: auto; padding: 25px; display: grid; grid-template-columns: repeat(2, 1fr); gap: 15px; align-content: start; }

        .card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.05); padding: 15px; position: relative; transition: background 0.2s; }
        .card.full { grid-column: span 2; }
        .card:hover { border-color: rgba(200,170,110,0.3); background: rgba(255,255,255,0.06); }
        .row { display: flex; margin-bottom: 8px; font-size: 13px; align-items: baseline; border-bottom: 1px dashed rgba(255,255,255,0.05); padding-bottom: 4px; }
        .row:last-child { margin-bottom: 0; border-bottom: none; }
        .k { color: #888; width: 90px; flex-shrink: 0; font-weight: bold; }
        .v { color: #ddd; flex: 1; line-height: 1.4; word-break: break-word; }
        .inner-scroll { max-height: 150px; overflow-y: auto; padding-right: 5px; border: 1px solid rgba(255,255,255,0.05); background: rgba(0,0,0,0.2); padding: 8px; margin-top: 5px; }
        .tag-status { font-size: 10px; padding: 1px 6px; border: 1px solid #555; border-radius: 3px; margin-left: auto; color: #aaa; background: rgba(0,0,0,0.4); }

        .random-event-container { display: flex; gap: 10px; margin-top: 5px; }
        .re-box { flex: 1; padding: 10px; border-radius: 4px; border: 1px solid rgba(255,255,255,0.1); display: flex; flex-direction: column; align-items: center; text-align: center; }
        .re-label { font-size: 10px; color: #888; margin-bottom: 4px; text-transform: uppercase; }
        .re-val { font-size: 12px; font-weight: bold; color: #eee; }
        .re-name { background: rgba(50, 40, 60, 0.4); border-color: var(--c-sub); }
        .re-status { background: rgba(60, 40, 20, 0.4); border-color: #e67e22; }
        .re-cond { background: rgba(20, 40, 50, 0.4); border-color: var(--c-blue-mana); }

        /* ==================== Hệ thống phù văn ==================== */
        .stat-rune-container { display: grid; grid-template-columns: repeat(4, 1fr); gap: 15px; margin-top: 20px; padding: 0 10px; }
        .rune-card { display: flex; flex-direction: column; align-items: center; position: relative; }
        .rune-wrapper { width: 80px; height: 80px; position: relative; display: flex; justify-content: center; align-items: center; }
        .rune-bg-ring { position: absolute; inset: 0; border: 1px dashed rgba(255,255,255,0.1); border-radius: 50%; animation: rune-spin 10s linear infinite; }
        .rune-bg-ring::after { content: ''; position: absolute; top: -2px; left: 50%; width: 4px; height: 4px; background: currentColor; box-shadow: 0 0 5px currentColor; border-radius: 50%; }
        .progress-ring { width: 100%; height: 100%; }
        .progress-ring__circle { transition: stroke-dashoffset 0.8s cubic-bezier(0.4, 0, 0.2, 1); transform: rotate(-90deg); transform-origin: 50% 50%; fill: transparent; }
        .rune-val { position: absolute; font-family: var(--f-eng); font-size: 18px; font-weight: bold; color: #fff; text-shadow: 0 0 10px currentColor; z-index: 5; }
        .rune-name { margin-top: 8px; font-size: 11px; color: #888; letter-spacing: 1px; text-transform: uppercase; font-family: var(--f-main); text-align: center; }

        .r-gold { color: #f1c40f; } .r-gold .progress-ring__circle { stroke: #f1c40f; filter: drop-shadow(0 0 3px #f1c40f); } .r-gold .rune-bg-ring { color: rgba(241, 196, 15, 0.3); }
        .r-blue { color: #3498db; } .r-blue .progress-ring__circle { stroke: #3498db; filter: drop-shadow(0 0 3px #3498db); } .r-blue .rune-bg-ring { color: rgba(52, 152, 219, 0.3); }
        .r-purple { color: #9b59b6; } .r-purple .progress-ring__circle { stroke: #9b59b6; filter: drop-shadow(0 0 3px #9b59b6); } .r-purple .rune-bg-ring { color: rgba(155, 89, 182, 0.3); }
        .r-red { color: #e74c3c; } .r-red .progress-ring__circle { stroke: #e74c3c; filter: drop-shadow(0 0 4px #e74c3c); } .r-red .rune-bg-ring { color: rgba(231, 76, 60, 0.3); }
        @keyframes rune-spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

        /* Khu vực có thể thu gọn */
        .spoiler-section { border: 1px dashed rgba(200, 170, 110, 0.3); background: rgba(0,0,0,0.2); margin-top: 8px; border-radius: 4px; overflow: hidden; }
        .spoiler-header { padding: 8px 12px; background: rgba(255,255,255,0.03); cursor: pointer; display: flex; justify-content: space-between; align-items: center; font-size: 12px; color: #aaa; transition: background 0.3s; }
        .spoiler-header:hover { background: rgba(200, 170, 110, 0.1); color: var(--c-gold); }
        .spoiler-header i { transition: transform 0.3s; }
        .spoiler-section.open .spoiler-header i { transform: rotate(180deg); color: var(--c-gold); }
        .spoiler-content { max-height: 0; overflow: hidden; transition: max-height 0.4s ease-out, opacity 0.4s; opacity: 0; padding: 0 12px; border-top: 1px solid transparent; }
        .spoiler-section.open .spoiler-content { max-height: 500px; opacity: 1; padding: 12px; border-top-color: rgba(255,255,255,0.05); font-style: italic; color: #ccc; font-size: 13px; }

        /* ==================== Thích ứng thiết bị di động ==================== */
        @media screen and (max-width: 768px) {
            .hud-top { flex-direction: column; height: auto; padding: 15px 15px; gap: 15px; align-items: stretch; background: linear-gradient(to bottom, rgba(0,0,0,0.9), transparent); }
            .char-section { max-width: 100%; width: 100%; margin-bottom: 0; }
            .avatar-container { width: 60px; height: 60px; }
            .p-name { font-size: 18px; line-height: 1.2; word-break: break-all; }
            .resource-group { width: 100%; gap: 8px; justify-content: space-between; }
            .res-box { min-width: 0; flex: 1; padding: 6px 4px; flex-direction: column; align-items: center; gap: 4px; text-align: center; }
            .res-info { align-items: center; }
            .res-icon { font-size: 16px; width: auto; }
            /* Sửa đổi thích ứng: Bắt buộc không xuống dòng, và giảm cỡ chữ để phù hợp với văn bản dài */
            .rn { font-size: 12px; white-space: nowrap; }
            .rl { font-size: 9px; transform: scale(0.9); opacity: 0.8; }
            .compass-wrap { transform: scale(0.65); }
            .panel-content { grid-template-columns: 1fr; padding: 15px; padding-bottom: 60px; }
            .card.full { grid-column: auto; }
            #layer-detail { width: 96%; height: 85%; }
            .close-btn { width: 40px; height: 40px; font-size: 18px; }
            .stat-rune-container { grid-template-columns: repeat(2, 1fr); gap: 15px; justify-items: center; }
            .rune-wrapper { width: 64px; height: 64px; }
            .rune-val { font-size: 14px; }
            .rune-name { font-size: 10px; margin-top: 4px; }
            #music-panel, #settings-panel { width: 90vw; }
            #music-panel { left: -100vw; }
            #settings-panel { right: -100vw; }
            .ctrl-btn-group { bottom: -12px; }
            .mini-btn { width: 32px; height: 32px; font-size: 12px; }
        }
    </style>
</head>
<body>

    <div id="background-layer">
        <div class="bg-nebula"></div>
        <div class="bg-hex"></div>
        <div class="particles"></div>
        <div class="bg-grid"></div>
    </div>

    <div id="cursor-glow"></div>

    <div class="corner-decor c-tl"></div>
    <div class="corner-decor c-tr"></div>
    <div class="corner-decor c-bl"></div>
    <div class="corner-decor c-br"></div>

    <div id="music-panel" class="side-panel">
        <div class="panel-h">
            <span><i class="fa-solid fa-music"></i>Trình phát nhạc</span>
            <i class="fa-solid fa-xmark" onclick="toggleMusicPanel()"></i>
        </div>
        <div class="mp-controls">
            <i class="fa-solid fa-backward-step mp-btn" onclick="musicCtrl.prev()"></i>
            <div class="play-btn mp-btn" onclick="musicCtrl.toggle()">
                <i class="fa-solid fa-play" id="mp-play-icon"></i>
            </div>
            <i class="fa-solid fa-forward-step mp-btn" onclick="musicCtrl.next()"></i>
            <i class="fa-solid fa-repeat mp-btn" id="mp-loop-icon" title="Chế độ lặp lại" onclick="musicCtrl.toggleLoop()"></i>
        </div>
        <div class="mp-progress-container">
            <span id="mp-time-curr">00:00</span>
            <input type="range" class="mp-slider" id="mp-progress" value="0" min="0" max="100" step="1" oninput="musicCtrl.seek(this.value)">
            <span id="mp-time-total">00:00</span>
        </div>
        <div class="mp-list" id="mp-playlist"></div>
        <div class="mp-add">
            <input type="text" class="mp-input" id="mp-url-input" placeholder="Nhập địa chỉ URL nhạc...">
            <button class="mp-add-btn" onclick="musicCtrl.addFromInput()"><i class="fa-solid fa-plus"></i></button>
