    <script src="https://lib.baomitu.com/jquery/3.6.0/jquery.min.js"></script>
    <script src="https://lib.baomitu.com/jqueryui/1.13.2/jquery-ui.min.js"></script>
    <script type="module">
    /* ==================== Trình điều khiển cài đặt ==================== */
    window.settingsCtrl = {
        themes: {
            arcane: { gold: '#c8aa6e', shine: '#f0e6d2', sub: '#8a63cc', subDark: '#140d1c', bg: '#050306' },
            cyber:  { gold: '#00cec9', shine: '#81ecec', sub: '#0984e3', subDark: '#001015', bg: '#000000' },
            blood:  { gold: '#ff7675', shine: '#fab1a0', sub: '#d63031', subDark: '#1e0505', bg: '#0a0000' },
            void:   { gold: '#a29bfe', shine: '#dfe6e9', sub: '#6c5ce7', subDark: '#100c25', bg: '#050510' }
        },
        setTheme: function(name, btn) {
            const t = this.themes[name];
            const r = document.documentElement;
            r.style.setProperty('--c-gold', t.gold);
            r.style.setProperty('--c-gold-shine', t.shine);
            r.style.setProperty('--c-sub', t.sub);
            r.style.setProperty('--c-sub-dark', t.subDark);
            r.style.setProperty('--c-bg', t.bg);
            r.style.setProperty('--c-gold-dim', this.adjustColor(t.gold, -60));
            $(btn).siblings().removeClass('active');
            $(btn).addClass('active');
        },
        setFont: function(type, btn) {
            const r = document.documentElement;
            if(type === 'serif') r.style.setProperty('--f-main', "'Noto Serif SC', serif");
            if(type === 'sans') r.style.setProperty('--f-main', "'Helvetica Neue', Arial, sans-serif");
            if(type === 'tech') r.style.setProperty('--f-main', "'Orbitron', sans-serif");
            $(btn).siblings().removeClass('active');
            $(btn).addClass('active');
        },
        setPerf: function(mode, btn) {
            if(mode === 'low') $('body').addClass('low-perf');
            else $('body').removeClass('low-perf');
            $(btn).siblings().removeClass('active');
            $(btn).addClass('active');
        },
        adjustColor: function(col, amt) {
            let usePound = false;
            if (col[0] == "#") { col = col.slice(1); usePound = true; }
            let num = parseInt(col,16);
            let r = (num >> 16) + amt;
            if (r > 255) r = 255; else if  (r < 0) r = 0;
            let b = ((num >> 8) & 0x00FF) + amt;
            if (b > 255) b = 255; else if  (b < 0) b = 0;
            let g = (num & 0x0000FF) + amt;
            if (g > 255) g = 255; else if (g < 0) g = 0;
            return (usePound?"#":"") + (g | (b << 8) | (r << 16)).toString(16);
        }
    };

    /* ==================== Trình phát nhạc ==================== */
    window.musicCtrl = {
        playlist:[{name:"Nhạc nền CK2 Băng và Lửa",url:"https://files.catbox.moe/tobht3.ogg"},{name:"Khúc dạo đầu của Vong linh",url:"https://files.catbox.moe/dztvpv.MP3"},{name:"Yu-Gi-Oh 1",url:"https://files.catbox.moe/ng5856.mp3"},{name:"Yu-Gi-Oh 2",url:"https://files.catbox.moe/eub7xm.mp3"}],
        currentIdx:0, audio:new Audio, loopMode:1,
        init:function(){
            this.audio.addEventListener("ended",(()=>{2===this.loopMode?(this.audio.currentTime=0,this.audio.play()):1===this.loopMode?this.next():this.currentIdx<this.playlist.length-1?this.next():this.pause()}));
            this.audio.addEventListener("timeupdate",(()=>this.updateUI()));
            $("#mp-playlist").sortable({
                handle:".fa-grip-lines",
                update:function(t,e){
                    let s=[],i=musicCtrl.playlist[musicCtrl.currentIdx]?.url;
                    $("#mp-playlist .mp-item").each((function(){let t=$(this).data("url"),e=$(this).find("span").text();s.push({name:e,url:t})}));
                    musicCtrl.playlist=s; musicCtrl.currentIdx=musicCtrl.playlist.findIndex((t=>t.url===i));
                }
            });
            this.renderList();
        },
        renderList:function(){
            const t=$("#mp-playlist");t.empty();
            this.playlist.forEach(((e,s)=>{
                let i=s===this.currentIdx?"active":"";
                t.append(`<div class="mp-item ${i}" data-url="${e.url}" onclick="musicCtrl.playIndex(${s})">
                            <div style="display:flex;align-items:center;"><i class="fa-solid fa-grip-lines"></i><span>${e.name}</span></div>
                            <i class="fa-solid fa-trash del-btn" onclick="event.stopPropagation(); musicCtrl.remove(${s})"></i>
                        </div>`);
            }));
        },
        playIndex:function(t){t<0||t>=this.playlist.length||(this.currentIdx=t,this.audio.src=this.playlist[t].url,this.audio.play(),$("#mp-play-icon").attr("class","fa-solid fa-pause"),this.renderList())},
        toggle:function(){0!==this.playlist.length&&(this.audio.paused?(this.audio.src||this.playIndex(this.currentIdx),this.audio.play(),$("#mp-play-icon").attr("class","fa-solid fa-pause")):(this.audio.pause(),$("#mp-play-icon").attr("class","fa-solid fa-play")))},
        pause:function(){this.audio.pause(),$("#mp-play-icon").attr("class","fa-solid fa-play")},
        next:function(){let t=this.currentIdx+1;t>=this.playlist.length&&(t=0),this.playIndex(t)},
        prev:function(){let t=this.currentIdx-1;t<0&&(t=this.playlist.length-1),this.playIndex(t)},
        seek:function(t){this.audio.duration&&(this.audio.currentTime=t/100*this.audio.duration)},
        updateUI:function(){
            if(!this.audio.duration)return;
            const t=this.audio.currentTime/this.audio.duration*100;
            $("#mp-progress").val(t);
            const e=t=>{let e=Math.floor(t/60),s=Math.floor(t%60);return(e<10?"0"+e:e)+":"+(s<10?"0"+s:s)};
            $("#mp-time-curr").text(e(this.audio.currentTime)),$("#mp-time-total").text(e(this.audio.duration))
        },
        toggleLoop:function(){
            this.loopMode++,this.loopMode>2&&(this.loopMode=0);
            const t=$("#mp-loop-icon");
            0===this.loopMode?t.attr("class","fa-solid fa-arrow-right mp-btn").attr("title","Phát theo thứ tự"):1===this.loopMode?t.attr("class","fa-solid fa-repeat mp-btn active").attr("title","Lặp lại danh sách"):2===this.loopMode&&t.attr("class","fa-solid fa-1 mp-btn active").attr("title","Lặp lại một bài")
        },
        addFromInput:function(){
            const t=$("#mp-url-input").val().trim(); if(!t)return;
            const e="Track "+(this.playlist.length+1);
            this.playlist.push({name:e,url:t}),$("#mp-url-input").val(""),this.renderList(),1===this.playlist.length&&(this.currentIdx=0)
        },
        remove:function(t){this.playlist.splice(t,1),t===this.currentIdx?(this.pause(),this.audio.src="",this.playlist.length>0&&(this.currentIdx=t>=this.playlist.length?0:t)):t<this.currentIdx&&this.currentIdx--,this.renderList()}
    };

    /* ==================== Kiểm soát tương tác ==================== */
    window.toggleMusicPanel = function() { $('#music-panel').toggleClass('active'); $('#settings-panel').removeClass('active'); }
    window.toggleSettings = function() { $('#settings-panel').toggleClass('active'); $('#music-panel').removeClass('active'); }
    window.toggleSpoiler = function(el) { $(el).parent().toggleClass('open'); }
    window.restoreView = function() {
        $('#layer-detail').removeClass('active');
        setTimeout(() => { $('#layer-roulette').removeClass('shattered'); }, 300);
    }

    /* ==================== Logic cốt lõi (Phiên bản MVU) ==================== */
    // Hàm định dạng số：1000->1K, 1000000->1M
    function formatNum(num) {
        if (!num && num !== 0) return '0';
        num = Number(num);
        if (num >= 1000000) return (num / 1000000).toFixed(1).replace(/\.0$/, '') + 'M';
        if (num >= 1000) return (num / 1000).toFixed(1).replace(/\.0$/, '') + 'K';
        return num.toString();
    }

    async function init() {
        await waitGlobalInitialized('Mvu');
        musicCtrl.init();
        updateHUD();
        eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => {
            updateHUD();
            if ($('#layer-detail').hasClass('active')) {
                const lastType = $('#layer-detail').data('lastType');
                if(lastType) explodeTo(lastType);
            }
        });
    }

    // Cập nhật HUD từ biến MVU
    function updateHUD() {
        const allVars = getAllVariables();
        const root = _.get(allVars, 'stat_data', {});
        const hero = root.Nhân_vật_chính || {};
        const info = hero.Thông_tin_cơ_bản || {};

        $('#ui-name').text(info.Họ_tên || 'Unknown');

        let badgeHtml = '';
        const title = info.Danh_hiệu || 'Không';
        const rep = info.Đánh_giá_danh_vọng || 'Không';
        if (title !== 'Không') badgeHtml += `<div class="t-badge tb-title"><i class="fa-solid fa-medal"></i> ${title}</div>`;
        if (rep !== 'Không') badgeHtml += `<div class="t-badge tb-rep"><i class="fa-solid fa-bullhorn"></i> ${rep}</div>`;
        if (!badgeHtml) badgeHtml = `<div class="t-badge tb-norm">Tạm thời không có danh hiệu đặc biệt</div>`;
        $('#ui-badges').html(badgeHtml);

        const calc = hero.Tính_toán_thực_lực || {};
        const mpPool = calc.Bể_năng_lượng || {};
        // Sử dụng formatNum để định dạng số
        $('#ui-origin').text(formatNum(hero.Lò_luyện_bản_nguyên || 0));
        $('#ui-mp').text(`${formatNum(mpPool.Giá_trị_hiện_tại || 0)}/${formatNum(mpPool.Giá_trị_tối_đa || 0)}`);
        $('#ui-rank').text(calc.Đánh_giá_thực_lực || 'Phàm tục');
    }

    // Hiển thị bảng chi tiết
    window.explodeTo = function(type) {
        $('#layer-roulette').addClass('shattered');
        $('#layer-detail').data('lastType', type);

        const allVars = getAllVariables();
        const root = _.get(allVars, 'stat_data', {});
        const world = root.Thế_giới || {};
        const hero = root.Nhân_vật_chính || {};
        const chars = root.Đồ_giám || {};

        // Ánh xạ tên giai vị
        const RANK_NAMES = ['Phàm tục', 'Thức tỉnh', 'Sơ chưởng', 'Siêu phàm', 'Cực ý', 'Thăng hoa', 'Bán thần', 'Thần lực yếu ớt', 'Thần lực trung bình', 'Siêu thần cấp', 'Ngụy thánh vị', 'Chân thánh vị', 'Chung cực'];

        // Ánh xạ màu sắc phẩm chất
        const QUALITY_COLORS = {
            'Phàm tục': '#b0b0b0',
            'Tinh lương': '#2ecc71',
            'Hiếm có': '#3498db',
            'Huy ngân': '#dfe6e9',
            'Sử thi': '#9b59b6',
            'Truyền thuyết': '#e67e22',
            'Thần thoại': '#e74c3c',
            'Thánh diệu': '#f1c40f'
        };

        let title = '';
        let html = '';
        const row = (k,v) => `<div class="row"><span class="k">${k}</span><span class="v">${v || 'Không'}</span></div>`;

        if(type === 'world') {
            title = '<i class="fa-solid fa-globe"></i> Tình báo thế giới';
            const base = world.Thông_tin_cơ_bản || {};
            const random = world.Sự_kiện_ngẫu_nhiên || {};

            html += `<div class="card full">
                <div style="color:var(--c-gold); font-size:16px; margin-bottom:10px; font-weight:bold; border-bottom:1px solid #333; padding-bottom:5px;">
                    <i class="fa-solid fa-location-dot"></i> ${base.Vị_trí_hiện_tại || 'Chưa biết'}
                </div>
                ${row('Thời gian hiện tại', base.Thời_gian_hiện_tại)}
                ${row('Sự kiện thế giới', base.Sự_kiện_thế_giới)}
            </div>`;
            html += `<div class="card full">
                <div class="row"><span class="k">Lời tiên tri và tin đồn</span><span class="v" style="font-style:italic; color:var(--c-sub)">"${base.Lời_tiên_tri_và_tin_đồn || 'Không'}"</span></div>
            </div>`;
            html += `<div class="card full">
                <div style="color:#eee; font-weight:bold; font-size:13px;"><i class="fa-solid fa-dice"></i> Phán định sự kiện ngẫu nhiên</div>
                <div class="random-event-container">
                    <div class="re-box re-name"><span class="re-label">Sự kiện</span><span class="re-val">${random.Tên_sự_kiện || 'Không'}</span></div>
                    <div class="re-box re-status"><span class="re-label">Trạng thái</span><span class="re-val">${random.Trạng_thái || 'Chưa dính líu'}</span></div>
                    <div class="re-box re-cond"><span class="re-label">Điều kiện</span><span class="re-val">${random.Điều_kiện_kết_thúc || 'Không'}</span></div>
                </div>
                <div style="margin-top:8px; font-size:12px; color:#aaa; font-style:italic;">${random.Mô_tả || ''}</div>
            </div>`;
        }
        else if(type === 'self') {
            title = '<i class="fa-solid fa-id-card"></i> Hồ sơ cá nhân';
            const info = hero.Thông_tin_cơ_bản || {};
            const status = info.Trạng_thái_hiện_tại || {};
            const mpAttr = _.get(hero, 'Tính_toán_thực_lực.Bể_năng_lượng.Thuộc_tính', 'Không');
            const relations = hero.Mạng_lưới_quan_hệ || {};
            const items = hero.Túi_đồ || {};

            html += `<div class="card">
                ${row('Tình trạng sức khỏe', status.Tình_trạng_sức_khỏe)}
                ${row('Trạng thái đặc biệt', status.Trạng_thái_đặc_biệt)}
                ${row('Thuộc tính năng lượng', mpAttr)}
                ${row('Trang phục và ngoại hình', info.Trang_phục_và_ngoại_hình)}
            </div>`;

            html += `<div class="card">
                <div style="color:var(--c-gold); font-weight:bold; margin-bottom:8px; display:flex; justify-content:space-between;">
                    <span>Mạng lưới quan hệ xã hội</span>
                    <span style="font-size:10px; background:#333; padding:0 4px; border-radius:2px;">${Object.keys(relations).length}</span>
                </div>
                <div class="inner-scroll">
                    ${Object.keys(relations).length > 0 ? Object.entries(relations).map(([k,v]) =>
                        `<div style="display:flex; justify-content:space-between; font-size:12px; margin-bottom:6px; border-bottom:1px solid rgba(255,255,255,0.05); padding-bottom:2px;">
                            <span style="color:#eee; font-weight:bold;">${k.replace(/_/g, ' ')}</span><span style="color:#aaa">${v}</span>
                        </div>`
                    ).join('') : '<span style="color:#555; font-style:italic;">Tạm không có ghi chép quan hệ</span>'}
                </div>
            </div>`;

            html += `<div class="card full">
                <div style="color:var(--c-gold); font-weight:bold; margin-bottom:8px;">Vật phẩm mang theo</div>
                <div class="inner-scroll" style="max-height:200px;">
                    ${Object.keys(items).length > 0 ? Object.entries(items).map(([name, detail]) => {
                        const q = detail.Phẩm_chất || 'Phàm tục';
                        const c = QUALITY_COLORS[q] || '#b0b0b0';
                        return `<div style="background:rgba(0,0,0,0.3); padding:8px; margin-bottom:6px; border-left:2px solid ${c};">
                            <div style="display:flex; justify-content:space-between; align-items:center;">
                                <span style="font-weight:bold; color:#dcd6f7;">${name.replace(/_/g, ' ')}</span>
                                <div>
                                    <span class="tag-status" style="border-color:${c}; color:${c};">${q}</span>
                                    <span class="tag-status" style="margin-left:5px;">x${detail.Số_lượng}</span>
                                </div>
                            </div>
                            <div style="font-size:11px; color:#888; margin-top:2px;">${detail.Mô_tả}</div>
                        </div>`
                    }).join('') : '<span style="color:#555; font-style:italic; padding:10px;">Ba lô trống rỗng...</span>'}
                </div>
            </div>`;
        }
        else if(type === 'skills') {
            title = '<i class="fa-solid fa-wand-magic-sparkles"></i> Từ khóa siêu phàm';
            const skills = hero.Từ_khóa_siêu_phàm || {};
            if(Object.keys(skills).length === 0) {
                html = '<div class="card full" style="text-align:center; padding:30px; color:#555;">Tạm chưa thức tỉnh năng lực siêu phàm</div>';
            } else {
                Object.entries(skills).forEach(([name, detail]) => {
                    const rankVal = Math.min(Math.max(0, detail.Giá_trị_giai_vị || 0), 12);
                    const rankName = RANK_NAMES[rankVal] || 'Chưa biết';
                    let typeTag = `<span class="tag-status" style="border-color:#e67e22; color:#e67e22; margin-right:5px;">${detail.Loại}</span>`;
                    html += `<div class="card full">
                        <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:6px;">
                            <span style="color:var(--c-gold); font-weight:bold; font-size:15px; text-shadow:0 0 5px rgba(200,170,110,0.3);">${name.replace(/_/g, ' ')}</span>
                            <div>${typeTag}<span class="tag-status" style="border-color:var(--c-sub); color:#dcd6f7;">${rankName}</span></div>
                        </div>
                        <div style="color:#bbb; font-size:13px; line-height:1.5;">${detail.Mô_tả}</div>
                        <div style="font-size:10px; color:#666; margin-top:4px;">Cường độ: ${formatNum(detail.Cường_độ_năng_lượng)} | Thuộc tính: ${detail.Thuộc_tính_năng_lượng}</div>
                    </div>`;
                });
            }
        }
        else if(type === 'enemies') {
             title = '<i class="fa-solid fa-skull"></i> Radar cường địch';
             const enemies = world.Đối_thủ_hiện_tại || {};
             if(Object.keys(enemies).length > 0) {
                 html += `<div class="card full" style="border-color:var(--c-red-alert); background:rgba(40,10,10,0.4);">
                    <div style="color:var(--c-red-alert); font-weight:bold; margin-bottom:8px; border-bottom:1px dashed var(--c-red-alert); padding-bottom:5px;">
                        <i class="fa-solid fa-triangle-exclamation"></i> Cảnh báo chạm trán
                    </div>`;
                 Object.entries(enemies).forEach(([name, detail]) => {
                    // Hiển thị danh sách năng lực
                    const abilities = detail.Năng_lực_quan_trọng || {};
                    let abilityHtml = '';
                    if(Object.keys(abilities).length > 0) {
                        abilityHtml = '<div style="display:flex; flex-wrap:wrap; gap:4px; margin-top:6px;">';
                        Object.entries(abilities).forEach(([k,v]) => {
                            abilityHtml += `<span style="font-size:10px; background:rgba(231,76,60,0.1); border:1px solid rgba(231,76,60,0.3); color:#ffaaaa; padding:2px 6px; border-radius:3px;" title="${v}">${k.replace(/_/g, ' ')}</span>`;
                        });
                        abilityHtml += '</div>';
                    }

                    html += `<div style="margin-bottom:12px; padding-bottom:10px; border-bottom:1px dashed rgba(231,76,60,0.2);">
                        <div style="display:flex; justify-content:space-between; align-items:center;">
                            <span style="font-weight:bold; color:#fff; font-size:14px;">${name.replace(/_/g, ' ')}</span>
                            <span class="tag-status" style="border-color:var(--c-red-alert); color:#ffaaaa;">${detail.Giai_vị}</span>
                        </div>
                        <div style="font-size:11px; color:#ccc; margin:4px 0;">Trạng thái: ${detail.Trạng_thái}</div>
                        <div style="height:4px; background:#333; border-radius:2px; overflow:hidden; margin-top:4px;">
                            <div style="width:${Math.min(100, (detail.Bể_năng_lượng?.Giá_trị_hiện_tại / detail.Bể_năng_lượng?.Giá_trị_tối_đa * 100)) || 0}%; height:100%; background:var(--c-red-alert);"></div>
                        </div>
                        ${abilityHtml}
                    </div>`;
                 });
                 html += `</div>`;
            } else {
                html += '<div class="card full" style="text-align:center; padding:30px; color:#555;">Không có phản ứng năng lượng cao thù địch trong phạm vi quét</div>';
            }
        }
        else if(type === 'forces') {
            title = '<i class="fa-solid fa-chess"></i> Thế lực xung quanh';
            const forces = world.Thế_lực_xung_quanh || {};

            if(Object.keys(forces).length === 0) {
                html += '<div class="card full" style="text-align:center; color:#555;">Tạm không có tình báo thế lực xung quanh</div>';
            } else {
                Object.entries(forces).forEach(([name, f]) => {
                    let c = '#aaa';
                    if((f.Trạng_thái || '').includes('Địch') || (f.Trạng_thái || '').includes('Ác')) c = '#ff6b6b';
                    if((f.Trạng_thái || '').includes('Hữu') || (f.Trạng_thái || '').includes('Thiện') || (f.Trạng_thái || '').includes('Lợi') || (f.Trạng_thái || '').includes('Bạn')) c = '#2ecc71';
                    html += `<div class="card full">
                        <div style="display:flex; justify-content:space-between; margin-bottom:5px; align-items:center;">
                            <b style="color:#eee; font-size:15px;">${name.replace(/_/g, ' ')}</b>
                            <span style="color:${c}; border:1px solid ${c}; font-size:10px; padding:1px 5px; border-radius:2px; background:rgba(0,0,0,0.3);">${f.Trạng_thái || 'Chưa biết'}</span>
                        </div>
                        <div style="color:#999; font-size:12px; padding-left:5px; border-left:2px solid #333;">${f.Động_thái_mới_nhất || 'Không có động thái'}</div>
                    </div>`;
                });
            }
        }
        else if(type === 'chars') {
            title = '<i class="fa-solid fa-users-viewfinder"></i> Phân tích mục tiêu';
            if(Object.keys(chars).length === 0) {
                html = '<div class="card full" style="text-align:center; color:#555;">Không có tín hiệu nhân vật quan trọng gần đây</div>';
            } else {
                Object.entries(chars).forEach(([name, c]) => {
                    let runesHtml = '';
                    const stats = c.Bốn_chiều_quan_hệ || {};
                    if(Object.keys(stats).length > 0) {
                        runesHtml = '<div class="stat-rune-container">';
                        const mapTheme = { 'Giá_trị_lợi_dụng': 'r-gold', 'Độ_kiểm_soát': 'r-blue', 'Lý_tính': 'r-blue', 'Độ_phụ_thuộc': 'r-purple', 'Cảm_tính': 'r-purple', 'Mức_độ_đe_dọa': 'r-red', 'Địch_ý': 'r-red' };
                        Object.entries(stats).forEach(([label, val]) => {
                            let theme = mapTheme[label] || 'r-gold';
                            const safeVal = Math.min(100, Math.max(0, Number(val)));
                            const radius = 32; const circumference = 2 * Math.PI * radius;
                            const offset = circumference - (safeVal / 100) * circumference;
                            runesHtml += `<div class="rune-card ${theme}">
                                <div class="rune-wrapper"><div class="rune-bg-ring"></div>
                                    <svg class="progress-ring" viewBox="0 0 80 80"><circle stroke="rgba(255,255,255,0.1)" stroke-width="4" fill="transparent" r="${radius}" cx="40" cy="40"/><circle class="progress-ring__circle" stroke-width="5" stroke-linecap="round" stroke-dasharray="${circumference} ${circumference}" stroke-dashoffset="${offset}" r="${radius}" cx="40" cy="40"/></svg>
                                    <div class="rune-val">${safeVal}</div>
                                </div><div class="rune-name">${label.replace(/_/g, ' ')}</div>
                            </div>`;
                        });
                        runesHtml += '</div>';
                    }
                    const secrets = c.Át_chủ_bài_bí_mật || {};
                    const secretHtml = Object.keys(secrets).length > 0
                        ? Object.entries(secrets).map(([k,v]) => `<div style="margin-bottom:6px; padding-bottom:4px; border-bottom:1px dashed #444; line-height:1.4;"><strong style="color:#dcd6f7">${k.replace(/_/g, ' ')}:</strong> ${v}</div>`).join('')
                        : '<span style="color:#666">Tạm thời chưa có át chủ bài nào bị lộ</span>';
                    html += `<div class="card full">
                        <div style="font-size:16px; font-weight:bold; margin-bottom:5px; color:var(--c-gold); display:flex; justify-content:space-between; align-items:center;">
                            <span>${name.replace(/_/g, ' ')}</span><small style="color:#888; font-weight:normal; font-family:monospace; border:1px solid #444; padding:0 4px; border-radius:3px;">${c.Thân_phận || 'Chưa biết'}</small>
                        </div>
                        ${runesHtml}
                        <div class="spoiler-section"><div class="spoiler-header" onclick="toggleSpoiler(this)"><span><i class="fa-regular fa-comment-dots"></i> Nội tâm độc thoại</span><i class="fa-solid fa-chevron-down"></i></div>
                            <div class="spoiler-content">"${c.Nội_tâm_OS || 'Không thể đọc được hoạt động nội tâm'}"</div></div>
                        <div class="spoiler-section"><div class="spoiler-header" onclick="toggleSpoiler(this)"><span><i class="fa-solid fa-user-secret"></i> Át chủ bài bí mật</span><i class="fa-solid fa-chevron-down"></i></div>
                            <div class="spoiler-content">${secretHtml}</div></div>
                    </div>`;
                });
            }
        }

        $('#d-title').html(title);
        $('#d-content').html(html);
        $('#layer-detail').addClass('active');
    }

    const cursor = document.getElementById('cursor-glow');
    let mouseX = -500, mouseY = -500, currentX = -500, currentY = -500;
    document.addEventListener('mousemove', (e) => { mouseX = e.clientX; mouseY = e.clientY; });
    function animateCursor() {
        currentX += (mouseX - currentX) * 0.15; currentY += (mouseY - currentY) * 0.15;
        if(cursor) cursor.style.transform = `translate3d(${currentX}px, ${currentY}px, 0) translate(-50%, -50%)`;
        requestAnimationFrame(animateCursor);
    }
    animateCursor();

    $(errorCatched(init));
    </script>
</body>
</html>
