scripts.content:
import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/variable_zod.js';

// === Anh trai, đây là trợ thủ nhỏ thêm vào để ngăn báo lỗi ===

// Nếu vị trí lẽ ra là đối tượng lại nhận được chuỗi, tự động điền defaultKey
const strToObj = (defaultKey, schema) =>
  z.preprocess(val => (typeof val === 'string' ? { [defaultKey]: val } : val), schema);

// Nếu vị trí lẽ ra là đối tượng lại nhận được số, tự động điền defaultKey
const numToObj = (defaultKey, schema) =>
  z.preprocess(val => (typeof val === 'number' ? { [defaultKey]: val } : val), schema);

// Nếu danh sách (Record) nhận được dữ liệu không phải đối tượng kỳ lạ, cung cấp một đối tượng trống để ngăn lỗi
const safeRecord = (schema) =>
  z.preprocess(val => (val && typeof val === 'object' && !Array.isArray(val) ? val : {}), schema);

// ========================================

const RANK_NAME_MAP = {
  0: 'Phàm tục', 1: 'Thức tỉnh', 2: 'Sơ chưởng', 3: 'Siêu phàm', 4: 'Cực ý', 5: 'Thăng hoa',
  6: 'Bán thần', 7: 'Thần lực yếu ớt', 8: 'Thần lực trung bình', 9: 'Siêu thần cấp', 10: 'Ngụy thánh vị', 11: 'Chân thánh vị', 12: 'Chung cực'
};

const RANK_ENERGY_CAP = {
  0: 90, 1: 300, 2: 1000, 3: 5000, 4: 12000, 5: 40000, 6: 70000,
  7: 120000, 8: 180000, 9: 300000, 10: 1000000, 11: 10000000, 12: 100000000
};

export const Schema = z.object({
  Thế_giới: z.object({
    Thông_tin_cơ_bản: strToObj('Sự_kiện_thế_giới', z.object({
      Thời_gian_hiện_tại: z.string().prefault('Chưa biết'),
      Vị_trí_hiện_tại: z.string().prefault('Chưa biết'),
      Sự_kiện_thế_giới: z.string().prefault('Không'),
      Lời_tiên_tri_và_tin_đồn: z.string().prefault('Không'),
    })),
    Sự_kiện_ngẫu_nhiên: strToObj('Mô_tả', z.object({
      Tên_sự_kiện: z.string().prefault('Không'),
      Trạng_thái: z.enum(['Đang tiến hành', 'Chưa dính líu', 'Đã hoàn thành']).prefault('Chưa dính líu'),
      Mô_tả: z.string().prefault('Không'),
      Điều_kiện_kết_thúc: z.string().prefault('Không'),
    })),
    Đối_thủ_hiện_tại: safeRecord(z.record(
      z.string(),
      strToObj('Trạng_thái', z.object({
        Giai_vị: z.string().prefault('Chưa biết'),
        Trạng_thái: z.string().prefault('Chưa biết'),
        Bể_năng_lượng: numToObj('Giá_trị_hiện_tại', z.object({
          Giá_trị_hiện_tại: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
          Giá_trị_tối_đa: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
          Thuộc_tính: z.string().prefault('Không'),
        })),
        Năng_lực_quan_trọng: safeRecord(z.record(z.string(), z.string())).prefault({}),
      }))
    ).prefault({})).transform(val => _(val).entries().takeRight(3).fromPairs().value()),
    Thế_lực_xung_quanh: safeRecord(z.record(
      z.string(),
      strToObj('Động_thái_mới_nhất', z.object({
        Trạng_thái: z.string().prefault('Chưa biết'),
        Động_thái_mới_nhất: z.string().prefault('Không'),
      }))
    ).prefault({})).transform(val => _(val).entries().takeRight(3).fromPairs().value()),
  }),
  Nhân_vật_chính: z.object({
    Thông_tin_cơ_bản: z.object({
      Họ_tên: z.string().prefault('Chưa biết'),
      Danh_hiệu: z.string().prefault('Không'),
      Đánh_giá_danh_vọng: z.string().prefault('Không'),
      Trang_phục_và_ngoại_hình: z.string().prefault('Không'),
      Trạng_thái_hiện_tại: strToObj('Tình_trạng_sức_khỏe', z.object({
        Tình_trạng_sức_khỏe: z.string().prefault('Khỏe mạnh'),
        Trạng_thái_đặc_biệt: z.string().prefault('Không'),
      })),
    }),
    Lò_luyện_bản_nguyên: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
    Túi_đồ: safeRecord(z.record(
      z.string().describe('Tên đồ vật'),
      strToObj('Mô_tả', z.object({
        Phẩm_chất: z.string().prefault('Phàm tục'),
        Mô_tả: z.string().prefault('Không'),
        Số_lượng: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
      }))
    ).prefault({})).transform(items => _.pickBy(items, item => item.Số_lượng > 0)),
    Từ_khóa_siêu_phàm: safeRecord(z.record(
      z.string(),
      z.object({
        Giá_trị_giai_vị: z.coerce.number().transform(v => _.clamp(v, 0, 12)).prefault(0),
        Cường_độ_năng_lượng: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
        Thuộc_tính_năng_lượng: z.string().prefault('Không'),
        Loại: z.string().prefault('Thông dụng'),
        Mô_tả: z.string().prefault('Không'),
      })
    ).prefault({})),
    Tính_toán_thực_lực: z.object({
      Bể_năng_lượng: numToObj('Giá_trị_hiện_tại', z.object({
        Giá_trị_hiện_tại: z.coerce.number().transform(v => Math.max(0, v)).prefault(10),
        Giá_trị_tối_đa: z.coerce.number().transform(v => Math.max(0, v)).prefault(10),
        Thuộc_tính: z.string().prefault('Thể lực'),
      })).prefault({ Giá_trị_hiện_tại: 10, Giá_trị_tối_đa: 10, Thuộc_tính: 'Thể lực' }),
      Đánh_giá_thực_lực: z.string().prefault('Phàm tục'),
    }).prefault({
      Bể_năng_lượng: { Giá_trị_hiện_tại: 10, Giá_trị_tối_đa: 10, Thuộc_tính: 'Thể lực' },
      Đánh_giá_thực_lực: 'Phàm tục'
    }),
    Mạng_lưới_quan_hệ: safeRecord(z.record(z.string(), z.string()).prefault({})),
  }),
  Đồ_giám: safeRecord(z.record(
    z.string(),
    strToObj('Nội_tâm_OS', z.object({
      Thân_phận: z.string().prefault('Chưa biết'),
      Nội_tâm_OS: z.string().prefault('...'),
      Bốn_chiều_quan_hệ: z.object({
        Giá_trị_lợi_dụng: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        Độ_kiểm_soát: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        Độ_phụ_thuộc: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        Mức_độ_đe_dọa: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      }).prefault({ Giá_trị_lợi_dụng: 0, Độ_kiểm_soát: 0, Độ_phụ_thuộc: 0, Mức_độ_đe_dọa: 0 }),
      Át_chủ_bài_bí_mật: safeRecord(z.record(z.string(), z.string())).prefault({}),
    }))
  ).prefault({})), // Ở đây đã bỏ giới hạn số lượng rồi nhé
}).transform(root => {
  const hero = root.Nhân_vật_chính;
  const abilities = _.values(hero.Từ_khóa_siêu_phàm);
  const maxRankAbility = _.maxBy(abilities, 'Giá_trị_giai_vị');
  const rawRankVal = maxRankAbility ? maxRankAbility.Giá_trị_giai_vị : 0;
  const displayRankVal = Math.min(rawRankVal, 11);
  const calculatedTotalEnergy = 10 + _.sumBy(abilities, 'Cường_độ_năng_lượng');
  const rankCap = RANK_ENERGY_CAP[displayRankVal] || 90;
  const finalMaxEnergy = Math.min(calculatedTotalEnergy, rankCap);
  const mainAttr = maxRankAbility ? maxRankAbility.Thuộc_tính_năng_lượng : 'Thể lực';

  // Đảm bảo bể năng lượng tồn tại và thuộc tính chính xác
  const pool = hero.Tính_toán_thực_lực?.Bể_năng_lượng || { Giá_trị_hiện_tại: finalMaxEnergy, Giá_trị_tối_đa: finalMaxEnergy, Thuộc_tính: 'Thể lực' };
  const currentEnergy = pool.Giá_trị_hiện_tại ?? finalMaxEnergy;
  const safeCurrentEnergy = _.clamp(currentEnergy, 0, finalMaxEnergy);

  hero.Tính_toán_thực_lực = {
    Bể_năng_lượng: {
      Giá_trị_hiện_tại: safeCurrentEnergy,
      Giá_trị_tối_đa: finalMaxEnergy,
      Thuộc_tính: mainAttr
    },
    Đánh_giá_thực_lực: RANK_NAME_MAP[displayRankVal] || 'Tồn tại chưa biết'
  };
  return root;
});

$(() => {
  registerMvuSchema(Schema);
})
